function candidate(left, right, generatedOnly) {
  const generatedLineOrder = left.generatedLine - right.generatedLine;
  if (generatedLineOrder !== 0) return generatedLineOrder;

  const generatedColumnOrder = left.generatedColumn - right.generatedColumn;
  if (generatedColumnOrder !== 0 || generatedOnly) return generatedColumnOrder;

  const textOrder = (first, second) => {
    if (first === second) return 0;
    if (first == null) return 1;
    if (second == null) return -1;
    return first > second ? 1 : -1;
  };

  const sourceOrder = textOrder(left.source, right.source);
  if (sourceOrder !== 0) return sourceOrder;

  const originalLineOrder = left.originalLine - right.originalLine;
  if (originalLineOrder !== 0) return originalLineOrder;

  const originalColumnOrder = left.originalColumn - right.originalColumn;
  if (originalColumnOrder !== 0) return originalColumnOrder;

  return textOrder(left.name, right.name);
}
